-- Migration 116: Seed Atlanta Rent Scrape Targets
-- Adds a unique constraint on (property_name, city) so the seed is idempotent,
-- then inserts 106 Atlanta apartment properties as scrape targets.
-- Uses listing_url for the source aggregator URL (apartments.com reference).
-- website_url is populated separately via the discover_property_urls Clawdbot command
-- which calls SerpAPI to find each property's official website.
-- Safe to re-run: ON CONFLICT (property_name, city) DO NOTHING.

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_constraint WHERE conname = 'uq_rent_scrape_targets_name_city'
  ) THEN
    ALTER TABLE rent_scrape_targets
      ADD CONSTRAINT uq_rent_scrape_targets_name_city UNIQUE (property_name, city);
  END IF;
END $$;

ON CONFLICT (property_name, city) DO NOTHING;
